  function isCcoRoutePath(pathname = '') {
    const normalized = String(pathname || '').trim().toLowerCase();
    return (
      normalized.endsWith('/cco') ||
      normalized.endsWith('/ccp') ||
      normalized.endsWith('/agents/cco') ||
      normalized.endsWith('/admin/cco')
    );
  }

  function isCcoNextRoutePath(pathname = '') {
    const normalized = String(pathname || '').trim().toLowerCase();
    return normalized.endsWith('/cco-next') || normalized.endsWith('/admin/cco-next');
  }

  function isUnansweredRoutePath(pathname = '') {
    void pathname;
    return false;
  }

  function getEventTargetElement(event = null) {
    if (!event) return null;
    const target = event.target;
    if (target instanceof Element) return target;
    if (target && target.parentElement instanceof Element) return target.parentElement;
    return null;
  }

  function closestFromEventTarget(event = null, selector = '') {
    const safeSelector = String(selector || '').trim();
    if (!safeSelector) return null;
    const targetEl = getEventTargetElement(event);
    if (!targetEl) return null;
    return targetEl.closest(safeSelector);
  }

  function asArray(value) {
    return Array.isArray(value) ? value : [];
  }

  function isCcoInteractionDebugEnabled() {
    const params = new URLSearchParams(window.location.search || '');
    if (params.get('cco_debug_clicks') === '1') return true;
    try {
      return localStorage.getItem('ARCANA_CCO_DEBUG_CLICKS') === '1';
    } catch {
      return false;
    }
  }

  function logCcoInteraction(eventName = '', payload = {}) {
    if (!isCcoInteractionDebugEnabled()) return;
    try {
      const stamp = new Date().toISOString();
      console.info(`[CCO click-debug] ${stamp} ${String(eventName || '').trim()}`, payload);
    } catch {
      // Ignore console failures.
    }
  }

  function readCcoViewModeFromLocation() {
    return 'all';
  }

  function readCcoThreadFromLocation() {
    if (
      !isCcoRoutePath(window.location.pathname || '') &&
      !isCcoNextRoutePath(window.location.pathname || '')
    ) {
      return '';
    }
    const searchParams = new URLSearchParams(window.location.search || '');
    return String(searchParams.get(CCO_THREAD_QUERY_PARAM) || '').trim();
  }


  function readCcoLastSeenAtMs() {
    try {
      const raw = String(localStorage.getItem(CCO_LAST_SEEN_AT_KEY) || '').trim();
      if (!raw) {
        const now = Date.now();
        persistCcoLastSeenAtMs(now);
        return now;
      }
      const parsed = Date.parse(raw);
      if (Number.isFinite(parsed)) return parsed;
      const now = Date.now();
      persistCcoLastSeenAtMs(now);
      return now;
    } catch {
      return Date.now();
    }
  }

  function persistCcoLastSeenAtMs(value = Date.now()) {
    const safeValue = Number(value);
    const iso = Number.isFinite(safeValue) ? new Date(safeValue).toISOString() : new Date().toISOString();
    try {
      localStorage.setItem(CCO_LAST_SEEN_AT_KEY, iso);
    } catch {
      // ignore localStorage failures
    }
    return iso;
  }

  function readCcoOnboardingCompleted() {
    try {
      return String(localStorage.getItem(CCO_ONBOARDING_COMPLETED_KEY) || '').trim().toLowerCase() === 'true';
    } catch {
      return false;
    }
  }

  function persistCcoOnboardingCompleted(completed = true) {
    try {
      localStorage.setItem(CCO_ONBOARDING_COMPLETED_KEY, completed === true ? 'true' : 'false');
    } catch {
      // ignore localStorage failures
    }
  }

  function readCcoWorkspaceSessionState() {
    try {
      const raw = sessionStorage.getItem(CCO_WORKSPACE_SESSION_KEY);
      if (!raw) return {};
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};
      return parsed;
    } catch {
      return {};
    }
  }

  function readArcanaUiBuildMarker() {
    const fromMeta = document
      .querySelector('meta[name="arcana-ui-build"]')
      ?.getAttribute('content');
    const safeMeta = String(fromMeta || '').trim();
    if (safeMeta) return safeMeta;
    const script = document.querySelector('script[src*="/admin.js"]');
    const src = String(script?.getAttribute('src') || '').trim();
    if (!src) return '';
    try {
      const url = new URL(src, window.location.origin);
      return String(url.searchParams.get('v') || '').trim();
    } catch {
      return '';
    }
  }

  function maybeResetArcanaUiClientState() {
    const params = new URLSearchParams(window.location.search || '');
    const shouldReset = params.get('arcana_reset') === '1';
    const buildKey = 'ARCANA_UI_BUILD';
    const build = readArcanaUiBuildMarker();
    try {
      const previousBuild = String(localStorage.getItem(buildKey) || '').trim();
      if (build && build !== previousBuild) {
        localStorage.setItem(buildKey, build);
      }
      if (!shouldReset) return false;
      sessionStorage.removeItem(CCO_WORKSPACE_SESSION_KEY);
      localStorage.removeItem(CCO_LAST_SEEN_AT_KEY);
      localStorage.removeItem(RISK_FILTERS_KEY);
      localStorage.removeItem(AUDIT_FILTERS_KEY);
      localStorage.removeItem(TEMPLATE_LIST_FILTERS_KEY);
      localStorage.removeItem(LIST_SCROLL_STATE_KEY);
      localStorage.removeItem(DENSITY_KEY);
      localStorage.removeItem(LANGUAGE_KEY);
    } catch {
      // Ignore storage failures (private mode etc).
    }
    params.delete('arcana_reset');
    const search = params.toString();
    const nextUrl = `${window.location.pathname}${search ? `?${search}` : ''}${window.location.hash || ''}`;
    window.location.replace(nextUrl);
    return true;
  }

  if (maybeResetArcanaUiClientState()) return;

  const initialCcoWorkspaceSession = readCcoWorkspaceSessionState();

  function sanitizeCcoDraftMap(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const entries = Object.entries(value)
      .slice(0, 50)
      .map(([conversationId, draft]) => [String(conversationId || '').trim(), String(draft || '')]);
    const safe = {};
    for (const [conversationId, draft] of entries) {
      if (!conversationId || !draft.trim()) continue;
      safe[conversationId] = draft.slice(0, 12000);
    }
    return safe;
  }

  function sanitizeCcoNextPreviewThreadStateMap(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const safe = {};
    const textKeys = [
      'owner',
      'handoffStatus',
      'activeEditor',
      'draftOwner',
      'draftUpdatedAt',
      'collisionState',
      'handoffRequest',
      'handoffTarget',
      'handoffNote',
      'handoffStatusDetail',
      'lifecycleStage',
      'nextActionLabel',
      'nextActionSummary',
      'lastActionTakenLabel',
      'lastActionTakenAt',
      'draftStateLabel',
      'latestInboundPreview',
      'medicalBlocker',
      'bookingState',
      'waitingOn',
      'slaStatus',
      'situationSummary',
      'customerContext',
      'internalNote',
      'responseAngle',
      'escalationRule',
      'caseType',
      'subject',
      'keyNote',
    ];
    const studioTextKeys = [
      'activeDialog',
      'strategyKey',
      'strategyLabel',
      'strategyReason',
      'objective',
      'desiredOutcome',
      'guardrail',
      'postSendState',
      'postSendQueue',
      'postSendWaitingOn',
      'postSendOwner',
      'postSendFollowUpDueAt',
      'recommendedTool',
      'templateKey',
      'templateLabel',
      'templateSummary',
      'templateDraftBody',
      'currentDraftBody',
      'editedDraftBody',
      'draftSource',
      'readinessTone',
      'readinessLabel',
      'readinessSummary',
      'readinessState',
      'policyStatus',
      'lastAppliedTemplateKey',
      'lastAppliedTemplateAt',
      'lastEditedAt',
      'lastSentAt',
      'signatureEditorProfileId',
      'aiContextSummary',
      'aiSuggestionLabel',
      'aiSuggestionReason',
      'aiSuggestionBody',
      'aiLastGeneratedAt',
      'aiAppliedAt',
      'snoozePresetKey',
      'snoozeUntilAt',
      'scheduledSendAt',
      'deleteRequestedAt',
      'deletedAt',
      'deletedReason',
    ];
    const summaryTextKeys = ['assignedTo', 'lifecycleStatus', 'lastCaseSummary', 'customerSince'];
    for (const [conversationIdRaw, entryRaw] of Object.entries(value).slice(0, 50)) {
      const conversationId = String(conversationIdRaw || '').trim();
      if (!conversationId || !entryRaw || typeof entryRaw !== 'object' || Array.isArray(entryRaw)) continue;
      const entry = {};
      for (const key of textKeys) {
        if (!Object.prototype.hasOwnProperty.call(entryRaw, key)) continue;
        const safeValue = String(entryRaw[key] || '').trim();
        if (!safeValue) continue;
        entry[key] = safeValue.slice(0, 2400);
      }
      for (const booleanKey of ['needsMedicalReview', 'followUpSuggested']) {
        if (!Object.prototype.hasOwnProperty.call(entryRaw, booleanKey)) continue;
        entry[booleanKey] = entryRaw[booleanKey] === true;
      }
      if (Object.prototype.hasOwnProperty.call(entryRaw, 'previewSummary')) {
        const rawSummary =
          entryRaw.previewSummary && typeof entryRaw.previewSummary === 'object' && !Array.isArray(entryRaw.previewSummary)
            ? entryRaw.previewSummary
            : {};
        const safeSummary = {};
        for (const key of summaryTextKeys) {
          const safeValue = String(rawSummary[key] || '').trim();
          if (!safeValue) continue;
          safeSummary[key] = safeValue.slice(0, 1200);
        }
        const interactionCount = Number(rawSummary.interactionCount);
        if (Number.isFinite(interactionCount) && interactionCount >= 0) {
          safeSummary.interactionCount = Math.round(interactionCount);
        }
        const engagementScore = Number(rawSummary.engagementScore);
        if (Number.isFinite(engagementScore) && engagementScore >= 0) {
          safeSummary.engagementScore = Math.max(0, Math.min(1, engagementScore));
        }
        if (Object.keys(safeSummary).length) {
          entry.previewSummary = safeSummary;
        }
      }
      if (Array.isArray(entryRaw.previewMessages)) {
        entry.previewMessages = entryRaw.previewMessages.slice(0, 24).map((message) => ({
          author: String(message?.author || '').trim().slice(0, 140),
          role: String(message?.role || '').trim().slice(0, 40),
          timestamp: String(message?.timestamp || '').trim().slice(0, 80),
          body: String(message?.body || '').trim().slice(0, 4000),
        }));
      }
      if (Array.isArray(entryRaw.previewHistory)) {
        entry.previewHistory = entryRaw.previewHistory.slice(0, 24).map((item) => ({
          label: String(item?.label || '').trim().slice(0, 160),
          timestamp: String(item?.timestamp || '').trim().slice(0, 80),
          excerpt: String(item?.excerpt || '').trim().slice(0, 2000),
        }));
      }
      if (Array.isArray(entryRaw.previewNotes)) {
        entry.previewNotes = entryRaw.previewNotes
          .slice(0, 24)
          .map((note) => ({
            id: String(note?.id || '').trim().slice(0, 120),
            category: String(note?.category || '').trim().slice(0, 80),
            priority: String(note?.priority || '').trim().slice(0, 40),
            title: String(note?.title || '').trim().slice(0, 200),
            content: String(note?.content || note?.note || '').trim().slice(0, 4000),
            timestamp: String(note?.timestamp || '').trim().slice(0, 80),
            tags: Array.isArray(note?.tags)
              ? note.tags
                  .slice(0, 8)
                  .map((item) => String(item || '').trim())
                  .filter(Boolean)
                  .map((item) => item.slice(0, 80))
              : [],
          }))
          .filter((note) => note.content);
      }
      if (Array.isArray(entryRaw.medicalFlags)) {
        entry.medicalFlags = entryRaw.medicalFlags
          .slice(0, 12)
          .map((item) => String(item || '').trim())
          .filter(Boolean)
          .map((item) => item.slice(0, 200));
      }
      if (Array.isArray(entryRaw.activeViewers)) {
        entry.activeViewers = entryRaw.activeViewers
          .slice(0, 6)
          .map((viewer) => ({
            id: String(viewer?.id || '').trim().slice(0, 80),
            name: String(viewer?.name || '').trim().slice(0, 120),
            action: String(viewer?.action || viewer?.status || '').trim().slice(0, 40),
            location: String(viewer?.location || viewer?.context || '').trim().slice(0, 120),
            durationSeconds: Math.max(
              0,
              Math.round(
                Number(
                  viewer?.durationSeconds != null
                    ? viewer.durationSeconds
                    : viewer?.duration_seconds || 0
                ) || 0
              )
            ),
          }))
          .filter((viewer) => viewer.name);
      }
      if (Array.isArray(entryRaw.suggestedSlots)) {
        entry.suggestedSlots = entryRaw.suggestedSlots
          .slice(0, 8)
          .map((item) => String(item || '').trim())
          .filter(Boolean)
          .map((item) => item.slice(0, 120));
      }
      if (Object.prototype.hasOwnProperty.call(entryRaw, 'previewStudio')) {
        const rawStudio =
          entryRaw.previewStudio && typeof entryRaw.previewStudio === 'object' && !Array.isArray(entryRaw.previewStudio)
            ? entryRaw.previewStudio
            : {};
        const safeStudio = {};
        for (const key of studioTextKeys) {
          const safeValue = String(rawStudio[key] || '').trim();
          if (!safeValue) continue;
          safeStudio[key] = safeValue.slice(0, 4000);
        }
        for (const booleanKey of ['isOpen', 'sendReady', 'isDeleted']) {
          if (!Object.prototype.hasOwnProperty.call(rawStudio, booleanKey)) continue;
          safeStudio[booleanKey] = rawStudio[booleanKey] === true;
        }
        for (const numberKey of ['wordCount', 'aiConfidence', 'aiVersion']) {
          if (!Object.prototype.hasOwnProperty.call(rawStudio, numberKey)) continue;
          const numberValue = Number(rawStudio[numberKey]);
          if (Number.isFinite(numberValue) && numberValue >= 0) safeStudio[numberKey] = numberValue;
        }
        if (Array.isArray(rawStudio.signatureProfiles)) {
          safeStudio.signatureProfiles = rawStudio.signatureProfiles
            .slice(0, 8)
            .map((entry) => ({
              id: String(entry?.id || '').trim().slice(0, 80),
              ownerKey: String(entry?.ownerKey || '').trim().slice(0, 80),
              name: String(entry?.name || '').trim().slice(0, 120),
              title: String(entry?.title || '').trim().slice(0, 120),
              greeting: String(entry?.greeting || '').trim().slice(0, 120),
              contact: String(entry?.contact || '').trim().slice(0, 240),
              email: String(entry?.email || '').trim().slice(0, 120),
              phone: String(entry?.phone || '').trim().slice(0, 80),
            }))
            .filter((entry) => entry.id);
        }
        if (Array.isArray(rawStudio.toneFilters)) {
          safeStudio.toneFilters = rawStudio.toneFilters
            .slice(0, 8)
            .map((entry) => String(entry || '').trim().toLowerCase())
            .filter(Boolean)
            .map((entry) => entry.slice(0, 80));
        }
        if (Array.isArray(rawStudio.aiContextUsed)) {
          safeStudio.aiContextUsed = rawStudio.aiContextUsed
            .slice(0, 8)
            .map((entry) => String(entry || '').trim())
            .filter(Boolean)
            .map((entry) => entry.slice(0, 160));
        }
        if (rawStudio.signatureEditorDraft && typeof rawStudio.signatureEditorDraft === 'object' && !Array.isArray(rawStudio.signatureEditorDraft)) {
          safeStudio.signatureEditorDraft = {
            id: String(rawStudio.signatureEditorDraft.id || '').trim().slice(0, 80),
            ownerKey: String(rawStudio.signatureEditorDraft.ownerKey || '').trim().slice(0, 80),
            name: String(rawStudio.signatureEditorDraft.name || '').trim().slice(0, 120),
            title: String(rawStudio.signatureEditorDraft.title || '').trim().slice(0, 120),
            greeting: String(rawStudio.signatureEditorDraft.greeting || '').trim().slice(0, 120),
            contact: String(rawStudio.signatureEditorDraft.contact || '').trim().slice(0, 240),
            email: String(rawStudio.signatureEditorDraft.email || '').trim().slice(0, 120),
            phone: String(rawStudio.signatureEditorDraft.phone || '').trim().slice(0, 80),
          };
        }
        if (Object.keys(safeStudio).length) {
          entry.previewStudio = safeStudio;
        }
      }
      if (Object.keys(entry).length) {
        safe[conversationId] = entry;
      }
    }
    return safe;
  }

  function sanitizeCcoNextPreviewIdList(value) {
    if (!Array.isArray(value)) return [];
    const safe = [];
    const seen = new Set();
    for (const entry of value.slice(0, 50)) {
      const normalized = String(entry || '').trim();
      if (!normalized || seen.has(normalized)) continue;
      seen.add(normalized);
      safe.push(normalized.slice(0, 200));
    }
    return safe;
  }

  function sanitizeCcoScrollMap(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const safe = {};
    for (const [conversationId, scrollTopRaw] of Object.entries(value).slice(0, 50)) {
      const conversationKey = String(conversationId || '').trim();
      const scrollTop = Number(scrollTopRaw);
      if (!conversationKey || !Number.isFinite(scrollTop) || scrollTop < 0) continue;
      safe[conversationKey] = Math.round(scrollTop);
    }
    return safe;
  }

  function sanitizeCcoDraftModeMap(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const safe = {};
    for (const [conversationIdRaw, modeRaw] of Object.entries(value).slice(0, 50)) {
      const conversationId = String(conversationIdRaw || '').trim();
      const mode = String(modeRaw || '').trim().toLowerCase();
      if (!conversationId) continue;
      if (!['short', 'warm', 'professional'].includes(mode)) continue;
      safe[conversationId] = mode;
    }
    return safe;
  }

  function sanitizeCcoSystemFlagMap(value) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const safe = {};
    for (const [conversationIdRaw, flagRaw] of Object.entries(value).slice(0, 200)) {
      const conversationId = String(conversationIdRaw || '').trim();
      if (!conversationId) continue;
      if (flagRaw === true || String(flagRaw || '').trim().toLowerCase() === 'true') {
        safe[conversationId] = true;
        continue;
      }
      if (flagRaw === false || String(flagRaw || '').trim().toLowerCase() === 'false') {
        safe[conversationId] = false;
      }
    }
    return safe;
  }

  function sanitizeCcoSystemPatternList(value = []) {
    const source = Array.isArray(value) ? value : [];
    const dedupe = new Set();
    const safe = [];
    for (const entry of source.slice(0, 200)) {
      const normalized = String(entry || '').trim().toLowerCase();
      if (!normalized || normalized.length < 2) continue;
      if (dedupe.has(normalized)) continue;
      dedupe.add(normalized);
      safe.push(normalized.slice(0, 240));
    }
    return safe;
  }

  function sanitizeCcoDeleteCapabilityStatus(value = null) {
    const source = value && typeof value === 'object' ? value : {};
    const deleteEnabled = source.deleteEnabled === true;
    const reason = String(source.reason || '').trim();
    const reasonCode = String(source.reasonCode || '').trim();
    return {
      deleteEnabled,
      reason: reason || '',
      reasonCode: reasonCode || '',
    };
  }

  function sanitizeCcoSignaturePreviewExpanded(value = false) {
    if (value === true || value === 1) return true;
    const normalized = String(value || '')
      .trim()
      .toLowerCase();
    return normalized === 'true' || normalized === '1';
  }

  function sanitizeCcoIncludeSignature(value = true) {
    if (value === true || value === 1) return true;
    if (value === false || value === 0) return false;
    const normalized = String(value || '')
      .trim()
      .toLowerCase();
    if (normalized === 'false' || normalized === '0') return false;
    return true;
  }

  function sanitizeCcoCenterReadTab(value = 'conversation') {
    const normalized = String(value || '').trim().toLowerCase();
    if (normalized === 'notes') return 'notes';
    if (normalized === 'history') return 'history';
    if (normalized === 'customer') return 'customer';
    return 'conversation';
  }

  function sanitizeCcoSidebarTab(value = 'overview') {
    const normalized = String(value || '').trim().toLowerCase();
    if (normalized === 'ai') return 'ai';
    if (normalized === 'medical') return 'medical';
    if (normalized === 'team') return 'team';
    return 'overview';
  }

  const CCO_LOCKED_MAILBOX_ALLOWLIST = Object.freeze([
    'egzona@hairtpclinic.com',
    'contact@hairtpclinic.com',
    'fazli@hairtpclinic.com',
    'info@hairtpclinic.com',
    'kons@hairtpclinic.com',
    'marknad@hairtpclinic.com',
  ]);
  const CCO_LOCKED_MAILBOX_ALLOWLIST_SET = new Set(
    CCO_LOCKED_MAILBOX_ALLOWLIST.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean)
  );

  function sanitizeCcoMailboxFilter(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (!normalized || normalized === 'all') return 'all';
    if (!CCO_LOCKED_MAILBOX_ALLOWLIST_SET.has(normalized)) return 'all';
    return normalized.slice(0, 320);
  }

  function sanitizeCcoSearchQuery(value = '') {
    return String(value || '')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 180);
  }

  function sanitizeCcoShowSystemMessages(value = false) {
    if (value === true || value === 1) return true;
    const normalized = String(value || '')
      .trim()
      .toLowerCase();
    return normalized === 'true' || normalized === '1';
  }

  function sanitizeCcoViewMode(value = '') {
    void value;
    return 'all';
  }

  const CCO_MAIL_VIEW_MODES = Object.freeze(['queue', 'inbound', 'sent']);

  function sanitizeCcoMailViewMode(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (CCO_MAIL_VIEW_MODES.includes(normalized)) return normalized;
    return 'queue';
  }

  const CCO_INDICATOR_VIEW_FILTERS = Object.freeze([
    'all',
    'new',
    'critical',
    'high',
    'medium',
    'handled',
  ]);

  function sanitizeCcoIndicatorViewFilter(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (CCO_INDICATOR_VIEW_FILTERS.includes(normalized)) return normalized;
    return 'all';
  }

  const CCO_INDICATOR_OVERRIDE_STATES = Object.freeze([
    'new',
    'medium',
    'high',
    'critical',
    'handled',
  ]);

  function sanitizeCcoIndicatorOverrideState(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (CCO_INDICATOR_OVERRIDE_STATES.includes(normalized)) return normalized;
    return '';
  }

  function sanitizeCcoIndicatorOverrideMap(value = null) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
    const safe = {};
    for (const [conversationIdRaw, rawOverride] of Object.entries(value).slice(0, 500)) {
      const conversationId = String(conversationIdRaw || '').trim();
      if (!conversationId) continue;
      const source = rawOverride && typeof rawOverride === 'object' ? rawOverride : {};
      const overrideState = sanitizeCcoIndicatorOverrideState(source.state || rawOverride);
      if (!overrideState) continue;
      const overrideBy = String(source.overrideBy || source.by || '').trim().slice(0, 120);
      const overrideAt = toIso(source.overrideAt || source.at) || new Date().toISOString();
      safe[conversationId] = {
        state: overrideState,
        overrideBy,
        overrideAt,
      };
    }
    return safe;
  }

  function sanitizeCcoSlaFilter(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (['all', 'breach', 'warning', 'safe', 'new'].includes(normalized)) {
      return normalized;
    }
    return 'all';
  }

  function sanitizeCcoLifecycleFilter(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (
      [
        'all',
        'new',
        'active_dialogue',
        'awaiting_reply',
        'follow_up_pending',
        'dormant',
        'handled',
        'archived',
      ].includes(normalized)
    ) {
      return normalized;
    }
    return 'all';
  }

  const CCO_DENSITY_MODES = Object.freeze(['focus', 'work', 'overview']);
  const CCO_DEFAULT_DENSITY_MODE = 'work';
  const CCO_VISUAL_LIMITS = Object.freeze({
    sprint: 3,
    high: 7,
    needs: 12,
    maxVisibleRows: 15,
  });

  function sanitizeCcoDensityMode(value = '') {
    const normalized = String(value || '').trim().toLowerCase();
    if (CCO_DENSITY_MODES.includes(normalized)) return normalized;
    return CCO_DEFAULT_DENSITY_MODE;
  }

  function defaultCcoSectionExpandedState() {
    return {
      sprint: true,
      high: true,
      needs: true,
      rest: false,
    };
  }

  function sanitizeCcoSectionExpandedState(value = null) {
    const fallback = defaultCcoSectionExpandedState();
    const safe = value && typeof value === 'object' && !Array.isArray(value) ? value : {};
    return {
      sprint: safe.sprint !== false,
      high: safe.high !== false,
      needs: safe.needs !== false,
      rest: safe.rest === true,
    };
  }


  function loadLanguage() {
    const raw = String(localStorage.getItem(LANGUAGE_KEY) || 'sv')
      .trim()
      .toLowerCase();
    return SUPPORTED_LANGUAGES.includes(raw) ? raw : 'sv';
  }

  function loadDensityMode() {
    const raw = String(localStorage.getItem(DENSITY_KEY) || 'regular')
      .trim()
      .toLowerCase();
    return raw === 'compact' ? 'compact' : 'regular';
  }

  function parseStorageJson(key, fallback) {
    try {
      const raw = localStorage.getItem(key);
      if (!raw) return fallback;
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return fallback;
      return parsed;
    } catch {
      return fallback;
    }
  }

  function loadRiskFilters() {
    const parsed = parseStorageJson(RISK_FILTERS_KEY, {});
    const minRiskLevel = Number.parseInt(String(parsed.minRiskLevel ?? '3'), 10);
    const maxRiskLevel = Number.parseInt(String(parsed.maxRiskLevel ?? '5'), 10);
    const sinceDays = Number.parseInt(String(parsed.sinceDays ?? '14'), 10);
    const ownerDecision = typeof parsed.ownerDecision === 'string' ? parsed.ownerDecision.trim() : '';
    const decision = typeof parsed.decision === 'string' ? parsed.decision.trim() : '';
    const category = typeof parsed.category === 'string' ? parsed.category.trim() : '';
    const state = typeof parsed.state === 'string' ? parsed.state.trim() : '';
    const reasonCode = typeof parsed.reasonCode === 'string' ? parsed.reasonCode.trim() : '';
    const search = typeof parsed.search === 'string' ? parsed.search.trim() : '';
    const minNormalized = Number.isFinite(minRiskLevel) ? Math.max(1, Math.min(5, minRiskLevel)) : 3;
    const maxNormalized = Number.isFinite(maxRiskLevel) ? Math.max(1, Math.min(5, maxRiskLevel)) : 5;
    return {
      minRiskLevel: Math.min(minNormalized, maxNormalized),
      maxRiskLevel: Math.max(minNormalized, maxNormalized),
      sinceDays: Number.isFinite(sinceDays) ? Math.max(0, Math.min(365, sinceDays)) : 14,
      ownerDecision,
      decision,
      category,
      state,
      reasonCode,
      search,
    };
  }

  function loadAuditFilters() {
    const parsed = parseStorageJson(AUDIT_FILTERS_KEY, {});
    const sinceDays = Number.parseInt(String(parsed.sinceDays ?? '14'), 10);
    const limit = Number.parseInt(String(parsed.limit ?? '200'), 10);
    return {
      search: typeof parsed.search === 'string' ? parsed.search : '',
      action: typeof parsed.action === 'string' ? parsed.action : '',
      actorUserId: typeof parsed.actorUserId === 'string' ? parsed.actorUserId : '',
      targetType: typeof parsed.targetType === 'string' ? parsed.targetType : '',
      outcome: typeof parsed.outcome === 'string' ? parsed.outcome : '',
      severity: typeof parsed.severity === 'string' ? parsed.severity : '',
      sinceDays: Number.isFinite(sinceDays) ? Math.max(0, Math.min(365, sinceDays)) : 14,
      limit: Number.isFinite(limit) ? Math.max(50, Math.min(500, limit)) : 200,
    };
  }

  function loadTemplateListFilters() {
    const parsed = parseStorageJson(TEMPLATE_LIST_FILTERS_KEY, {});
    const sort = typeof parsed.sort === 'string' ? parsed.sort : 'updated_desc';
    const view = String(parsed.view || 'table').trim() === 'card' ? 'card' : 'table';
    return {
      search: typeof parsed.search === 'string' ? parsed.search : '',
      category: typeof parsed.category === 'string' ? parsed.category : '',
      status: typeof parsed.status === 'string' ? parsed.status : '',
      sort,
      view,
    };
  }

  function loadListScrollState() {
    const parsed = parseStorageJson(LIST_SCROLL_STATE_KEY, {});
    const normalized = {};
    for (const [key, rawValue] of Object.entries(parsed)) {
      const value = Number(rawValue);
      if (!Number.isFinite(value) || value < 0) continue;
      normalized[key] = Math.round(value);
    }
    return normalized;
  }

